-- TYAA Stock migration-ready SQL
-- Dialect: MySQL/MariaDB compatible, UTF-8/utf8mb4
-- Source: https://docs.google.com/spreadsheets/d/1ie9mjPozrfHG0g-EVGnTFvLC87hcsdBREaIpNiiLfrQ/edit?usp=sharing
-- Tabs: 23; raw rows: 2327; normalized records: 2256

SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;

CREATE TABLE IF NOT EXISTS `migration_ready` (
  `migration_id` VARCHAR(32) NOT NULL PRIMARY KEY,
  `source_sheet_order` INT NULL,
  `source_sheet_name` VARCHAR(255) NULL,
  `source_gid` VARCHAR(32) NULL,
  `source_row` INT NULL,
  `source_block_start_col` INT NULL,
  `source_section` TEXT NULL,
  `item_code` VARCHAR(255) NULL,
  `item_name_model` TEXT NULL,
  `serial_no` TEXT NULL,
  `quantity_raw` VARCHAR(255) NULL,
  `quantity_value` DECIMAL(18,3) NULL,
  `quantity_unit` VARCHAR(64) NULL,
  `balance_raw` VARCHAR(255) NULL,
  `notes` TEXT NULL,
  `extra_text` TEXT NULL,
  `needs_review` TINYINT(1) NOT NULL DEFAULT 0,
  `review_reason` TEXT NULL,
  `original_row_text` LONGTEXT NULL,
  `source_url` TEXT NULL,
  INDEX `idx_migration_ready_source` (`source_sheet_order`, `source_row`),
  INDEX `idx_migration_ready_review` (`needs_review`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `review_flags` LIKE `migration_ready`;

CREATE TABLE IF NOT EXISTS `source_tabs` (
  `source_sheet_order` INT NOT NULL PRIMARY KEY,
  `source_sheet_name` VARCHAR(255) NULL,
  `source_gid` VARCHAR(32) NULL,
  `raw_non_empty_rows` INT NULL,
  `raw_width` INT NULL,
  `normalized_records` INT NULL,
  `detected_blocks` INT NULL,
  `header_row_used` INT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `duplicate_serials` (
  `id` BIGINT NOT NULL AUTO_INCREMENT PRIMARY KEY,
  `serial_no` VARCHAR(255) NULL,
  `count` INT NULL,
  `migration_id` VARCHAR(32) NULL,
  `source_sheet_name` VARCHAR(255) NULL,
  `source_row` INT NULL,
  `item_name_model` TEXT NULL,
  INDEX `idx_duplicate_serials_serial` (`serial_no`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `data_dictionary` (
  `column` VARCHAR(128) NOT NULL PRIMARY KEY,
  `definition` TEXT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `raw_all_rows` (
  `id` BIGINT NOT NULL AUTO_INCREMENT PRIMARY KEY,
  `source_sheet_order` INT NULL,
  `source_sheet_name` VARCHAR(255) NULL,
  `source_gid` VARCHAR(32) NULL,
  `source_row` INT NULL,
  `non_empty_cells` INT NULL,
  `original_row_text` LONGTEXT NULL,
  `c01` TEXT NULL,
  `c02` TEXT NULL,
  `c03` TEXT NULL,
  `c04` TEXT NULL,
  `c05` TEXT NULL,
  `c06` TEXT NULL,
  `c07` TEXT NULL,
  `c08` TEXT NULL,
  `c09` TEXT NULL,
  `c10` TEXT NULL,
  `c11` TEXT NULL,
  `c12` TEXT NULL,
  `c13` TEXT NULL,
  `c14` TEXT NULL,
  `c15` TEXT NULL,
  `c16` TEXT NULL,
  `c17` TEXT NULL,
  `c18` TEXT NULL,
  `c19` TEXT NULL,
  `c20` TEXT NULL,
  `c21` TEXT NULL,
  `c22` TEXT NULL,
  INDEX `idx_raw_all_rows_source` (`source_sheet_order`, `source_row`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

SET FOREIGN_KEY_CHECKS = 1;














































