INSERT INTO `data_dictionary` (`column`, `definition`) VALUES
  ('migration_id', 'Stable generated key from sheet order, row number, and source block.'),
  ('source_sheet_name', 'Original Google Sheets tab name.'),
  ('source_row', 'Original 1-based row number inside the source tab CSV export.'),
  ('item_code', 'Original item number/code when detected.'),
  ('item_name_model', 'Cleaned item/model/name field inferred from the source row.'),
  ('serial_no', 'Detected S/N or Serial No. values, semicolon-separated when multiple are present.'),
  ('quantity_raw', 'Original quantity text exactly enough to audit units/notes.'),
  ('quantity_value', 'First parsed numeric quantity for import into numeric systems.'),
  ('quantity_unit', 'Unit text parsed after quantity, when available.'),
  ('balance_raw', 'Original balance/remaining quantity text when a separate balance column was detected.'),
  ('needs_review', 'TRUE when the row may be a header, merged multi-item row, missing quantity, or duplicate serial.'),
  ('original_row_text', 'Full source row text for audit and manual reconciliation.');
